class Solution:
    def isPathCrossing(self, path):
        x, y = 0, 0
        points = [(0, 0)]
        for ch in path:
            if ch == 'N':
                y += 1
            elif ch == 'S':
                y -= 1
            elif ch == 'E':
                x += 1
            else:
                x -= 1
            points.append((x, y))
        return len(set(points)) != len(points)

