class Solution:
    def isPathCrossing(self, path):
        x, y = 0, 0
        visited = {(0, 0)}
        moves = {'N': (0, 1), 'S': (0, -1), 'E': (1, 0), 'W': (-1, 0)}
        for ch in path:
            dx, dy = moves[ch]
            x += dx
            y += dy
            if (x, y) in visited:
                return True
            visited.add((x, y))
        return False

